import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/toggle/src/toggle.component.js';
const tagName = 'made-toggle';
Component.define(tagName);
/**
 * @summary Toggle is used to turn an item on or off.
 * @documentation '../../components/toggle/stories/toggle.mdx'
 *
 * @slot (default) - the toggle's label
 * @slot supporting-text - the toggle's supporting text
 *
 * @fires change {Event} - Fired whenever `selected` changes due to user interaction.
 * @fires input {Event} - Fired whenever `selected` changes due to user interaction.
 *
 * @csspart base - The component's base wrapper.
 * @csspart control - The control that houses the toggle's thumb.
 * @csspart thumb - The toggle's thumb.
 * @csspart label - The toggle's label.
 * @csspart supporting-text - The descriptive text's wrapper.
 *
 * @cssproperty --width - The width of the toggle.
 * @cssproperty --height - The height of the toggle.
 * @cssproperty --thumb-size - The size of the thumb.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onChange: 'change'
    },
    displayName: 'MadeToggle'
});
export default reactWrapper;
